func TestLoadConfig(t *testing.T) {
	// Save original environment
	origPort := os.Getenv("PORT")
	origMaxConcurrent := os.Getenv("MAX_CONCURRENT")
	origEnableTLS := os.Getenv("ENABLE_TLS")
	origCertFile := os.Getenv("TLS_CERT_FILE")
	origKeyFile := os.Getenv("TLS_KEY_FILE")
	origWorkloadURL := os.Getenv("WORKLOAD_MANAGER_URL")

	// Restore environment after test
	defer func() {
		os.Setenv("PORT", origPort)
		os.Setenv("MAX_CONCURRENT", origMaxConcurrent)
		os.Setenv("ENABLE_TLS", origEnableTLS)
		os.Setenv("TLS_CERT_FILE", origCertFile)
		os.Setenv("TLS_KEY_FILE", origKeyFile)
		os.Setenv("WORKLOAD_MANAGER_URL", origWorkloadURL)
	}()

	tests := []struct {
		name           string
		envVars        map[string]string
		expectedPort   int
		expectedMax    int
		expectedTLS    bool
		expectedCert   string
		expectedKey    string
		expectedURL    string
	}{
		{
			name:         "default values",
			envVars:      map[string]string{},
			expectedPort: 8080,
			expectedMax:  1000,
			expectedTLS:  false,
		},
		{
			name: "custom port",
			envVars: map[string]string{
				"PORT": "9090",
			},
			expectedPort: 9090,
			expectedMax:  1000,
			expectedTLS:  false,
		},
		{
			name: "custom max concurrent",
			envVars: map[string]string{
				"MAX_CONCURRENT": "500",
			},
			expectedPort: 8080,
			expectedMax:  500,
			expectedTLS:  false,
		},
		{
			name: "enable TLS",
			envVars: map[string]string{
				"ENABLE_TLS":   "true",
				"TLS_CERT_FILE": "/path/to/cert.pem",
				"TLS_KEY_FILE":  "/path/to/key.pem",
			},
			expectedPort: 8080,
			expectedMax:  1000,
			expectedTLS:  true,
			expectedCert: "/path/to/cert.pem",
			expectedKey:  "/path/to/key.pem",
		},
		{
			name: "workload manager URL",
			envVars: map[string]string{
				"WORKLOAD_MANAGER_URL": "http://localhost:8081",
			},
			expectedPort: 8080,
			expectedMax:  1000,
			expectedTLS:  false,
			expectedURL:  "http://localhost:8081",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Clear environment
			os.Unsetenv("PORT")
			os.Unsetenv("MAX_CONCURRENT")
			os.Unsetenv("ENABLE_TLS")
			os.Unsetenv("TLS_CERT_FILE")
			os.Unsetenv("TLS_KEY_FILE")
			os.Unsetenv("WORKLOAD_MANAGER_URL")

			// Set test environment
			for k, v := range tt.envVars {
				os.Setenv(k, v)
			}

			config := LoadConfig()

			if config.Port != tt.expectedPort {
				t.Errorf("LoadConfig() Port = %v, want %v", config.Port, tt.expectedPort)
			}
			if config.MaxConcurrentRequests != tt.expectedMax {
				t.Errorf("LoadConfig() MaxConcurrentRequests = %v, want %v", config.MaxConcurrentRequests, tt.expectedMax)
			}
			if config.EnableTLS != tt.expectedTLS {
				t.Errorf("LoadConfig() EnableTLS = %v, want %v", config.EnableTLS, tt.expectedTLS)
			}
			if tt.expectedCert != "" && config.CertFile != tt.expectedCert {
				t.Errorf("LoadConfig() CertFile = %v, want %v", config.CertFile, tt.expectedCert)
			}
			if tt.expectedKey != "" && config.KeyFile != tt.expectedKey {
				t.Errorf("LoadConfig() KeyFile = %v, want %v", config.KeyFile, tt.expectedKey)
			}
			if tt.expectedURL != "" && config.WorkloadManagerURL != tt.expectedURL {
				t.Errorf("LoadConfig() WorkloadManagerURL = %v, want %v", config.WorkloadManagerURL, tt.expectedURL)
			}
		})
	}
}

func TestGetEnvInt(t *testing.T) {
	tests := []struct {
		name         string
		value        string
		defaultValue int
		expected     int
	}{
		{
			name:         "valid integer",
			value:        "8080",
			defaultValue: 3000,
			expected:     8080,
		},
		{
			name:         "empty string uses default",
			value:        "",
			defaultValue: 3000,
			expected:     3000,
		},
		{
			name:         "invalid integer uses default",
			value:        "not-a-number",
			defaultValue: 3000,
			expected:     3000,
		},
		{
			name:         "negative number",
			value:        "-100",
			defaultValue: 3000,
			expected:     -100,
		},
		{
			name:         "zero value",
			value:        "0",
			defaultValue: 3000,
			expected:     0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var result int
			if tt.value == "" {
				result = getEnvInt("TEST_INT_VAR", tt.defaultValue)
			} else {
				os.Setenv("TEST_INT_VAR", tt.value)
				result = getEnvInt("TEST_INT_VAR", tt.defaultValue)
				os.Unsetenv("TEST_INT_VAR")
			}

			if result != tt.expected {
				t.Errorf("getEnvInt() = %v, want %v", result, tt.expected)
			}
		})
	}
}

func TestGetEnvBool(t *testing.T) {
	tests := []struct {
		name         string
		value        string
		defaultValue bool
		expected     bool
	}{
		{
			name:         "true value",
			value:        "true",
			defaultValue: false,
			expected:     true,
		},
		{
			name:         "false value",
			value:        "false",
			defaultValue: true,
			expected:     false,
		},
		{
			name:         "1 is true",
			value:        "1",
			defaultValue: false,
			expected:     true,
		},
		{
			name:         "0 is false",
			value:        "0",
			defaultValue: true,
			expected:     false,
		},
		{
			name:         "TRUE is true",
			value:        "TRUE",
			defaultValue: false,
			expected:     true,
		},
		{
			name:         "FALSE is false",
			value:        "FALSE",
			defaultValue: true,
			expected:     false,
		},
		{
			name:         "empty string uses default true",
			value:        "",
			defaultValue: true,
			expected:     true,
		},
		{
			name:         "empty string uses default false",
			value:        "",
			defaultValue: false,
			expected:     false,
		},
		{
			name:         "invalid value uses default",
			value:        "invalid",
			defaultValue: true,
			expected:     true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var result bool
			if tt.value == "" {
				result = getEnvBool("TEST_BOOL_VAR", tt.defaultValue)
			} else {
				os.Setenv("TEST_BOOL_VAR", tt.value)
				result = getEnvBool("TEST_BOOL_VAR", tt.defaultValue)
				os.Unsetenv("TEST_BOOL_VAR")
			}

			if result != tt.expected {
				t.Errorf("getEnvBool() = %v, want %v", result, tt.expected)
			}
		})
	}
}

