func TestNewSemaphore(t *testing.T) {
	tests := []struct {
		name     string
		capacity int
	}{
		{
			name:     "positive capacity",
			capacity: 10,
		},
		{
			name:     "capacity of 1",
			capacity: 1,
		},
		{
			name:     "large capacity",
			capacity: 10000,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			sem := NewSemaphore(tt.capacity)
			if sem == nil {
				t.Fatal("NewSemaphore() returned nil")
			}
			if sem.capacity != tt.capacity {
				t.Errorf("NewSemaphore() capacity = %v, want %v", sem.capacity, tt.capacity)
			}
			if sem.current != 0 {
				t.Errorf("NewSemaphore() current = %v, want 0", sem.current)
			}
		})
	}
}

func TestSemaphore_Acquire(t *testing.T) {
	tests := []struct {
		name        string
		capacity    int
		acquires    int
		wantSuccess []bool
	}{
		{
			name:        "acquire within capacity",
			capacity:    5,
			acquires:    3,
			wantSuccess: []bool{true, true, true},
		},
		{
			name:        "acquire at capacity",
			capacity:    3,
			acquires:    3,
			wantSuccess: []bool{true, true, true},
		},
		{
			name:        "acquire beyond capacity",
			capacity:    2,
			acquires:    3,
			wantSuccess: []bool{true, true, false},
		},
		{
			name:        "capacity of 1",
			capacity:    1,
			acquires:    2,
			wantSuccess: []bool{true, false},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			sem := NewSemaphore(tt.capacity)
			results := make([]bool, tt.acquires)

			for i := 0; i < tt.acquires; i++ {
				results[i] = sem.Acquire()
			}

			for i, want := range tt.wantSuccess {
				if results[i] != want {
					t.Errorf("Acquire() #%d = %v, want %v", i+1, results[i], want)
				}
			}
		})
	}
}

func TestSemaphore_Release(t *testing.T) {
	tests := []struct {
		name     string
		capacity int
	}{
		{
			name:     "release after acquire",
			capacity: 5,
		},
		{
			name:     "release single capacity",
			capacity: 1,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			sem := NewSemaphore(tt.capacity)

			// Acquire to capacity
			for i := 0; i < tt.capacity; i++ {
				if !sem.Acquire() {
					t.Fatalf("Failed to acquire #%d", i+1)
				}
			}

			// Next acquire should fail
			if sem.Acquire() {
				t.Error("Acquire() should fail at capacity")
			}

			// Release one
			sem.Release()

			// Now acquire should succeed
			if !sem.Acquire() {
				t.Error("Acquire() should succeed after release")
			}
		})
	}
}

func TestSemaphore_ConcurrentAccess(t *testing.T) {
	sem := NewSemaphore(10)
	var successCount int
	var mu sync.Mutex

	// Launch 20 goroutines trying to acquire
	var wg sync.WaitGroup
	for i := 0; i < 20; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			if sem.Acquire() {
				mu.Lock()
				successCount++
				mu.Unlock()
				// Hold for a short time
				time.Sleep(10 * time.Millisecond)
				sem.Release()
			}
		}()
	}

	wg.Wait()

	// Should have had at most 10 concurrent acquisitions
	if successCount > 20 {
		t.Errorf("Too many successful acquisitions: %d", successCount)
	}
}

func TestSemaphore_ThreadSafety(t *testing.T) {
	sem := NewSemaphore(100)
	iterations := 1000
	numGoroutines := 10

	var wg sync.WaitGroup
	for i := 0; i < numGoroutines; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for j := 0; j < iterations; j++ {
				if sem.Acquire() {
					sem.Release()
				}
			}
		}()
	}

	wg.Wait()

	// After all operations, current should be back to 0
	if sem.current != 0 {
		t.Errorf("Final current count = %d, want 0", sem.current)
	}
}

