// generateTestKeys creates a test RSA key pair
func generateTestKeys() (privateKeyPEM, publicKeyPEM []byte, err error) {
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return nil, nil, err
	}

	privateKeyBytes := x509.MarshalPKCS1PrivateKey(privateKey)
	privateKeyPEM = pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: privateKeyBytes,
	})

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(&privateKey.PublicKey)
	if err != nil {
		return nil, nil, err
	}

	publicKeyPEM = pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyBytes,
	})

	return privateKeyPEM, publicKeyPEM, nil
}

func TestNewJWTManager(t *testing.T) {
	privateKeyPEM, publicKeyPEM, err := generateTestKeys()
	if err != nil {
		t.Fatalf("Failed to generate test keys: %v", err)
	}

	tests := []struct {
		name           string
		privateKeyPEM  []byte
		publicKeyPEM   []byte
		wantErr        bool
		errContains    string
	}{
		{
			name:          "valid keys",
			privateKeyPEM: privateKeyPEM,
			publicKeyPEM:  publicKeyPEM,
			wantErr:       false,
		},
		{
			name:          "only private key",
			privateKeyPEM: privateKeyPEM,
			publicKeyPEM:  []byte{},
			wantErr:       false,
		},
		{
			name:          "only public key",
			privateKeyPEM: []byte{},
			publicKeyPEM:  publicKeyPEM,
			wantErr:       false,
		},
		{
			name:          "no keys",
			privateKeyPEM: []byte{},
			publicKeyPEM:  []byte{},
			wantErr:       false,
		},
		{
			name:          "invalid private key PEM",
			privateKeyPEM: []byte("invalid"),
			publicKeyPEM:  []byte{},
			wantErr:       true,
			errContains:   "failed to decode private key PEM",
		},
		{
			name:          "invalid public key PEM",
			privateKeyPEM: []byte{},
			publicKeyPEM:  []byte("invalid"),
			wantErr:       true,
			errContains:   "failed to decode public key PEM",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			manager, err := NewJWTManager(tt.privateKeyPEM, tt.publicKeyPEM)

			if tt.wantErr {
				if err == nil {
					t.Errorf("NewJWTManager() expected error but got none")
				} else if tt.errContains != "" && !containsSubstring(err.Error(), tt.errContains) {
					t.Errorf("NewJWTManager() error = %v, should contain %v", err, tt.errContains)
				}
			} else {
				if err != nil {
					t.Errorf("NewJWTManager() unexpected error = %v", err)
				}
				if manager == nil {
					t.Error("NewJWTManager() returned nil manager")
				}
			}
		})
	}
}

func TestJWTManager_SignToken(t *testing.T) {
	privateKeyPEM, publicKeyPEM, err := generateTestKeys()
	if err != nil {
		t.Fatalf("Failed to generate test keys: %v", err)
	}

	tests := []struct {
		name         string
		withPrivate  bool
		withPublic   bool
		claims       map[string]interface{}
		wantErr      bool
		errContains  string
	}{
		{
			name:        "sign with private key",
			withPrivate: true,
			withPublic:  false,
			claims:      map[string]interface{}{"user": "test"},
			wantErr:     false,
		},
		{
			name:        "sign without private key",
			withPrivate: false,
			withPublic:  true,
			claims:      map[string]interface{}{"user": "test"},
			wantErr:     true,
			errContains: "private key not configured",
		},
		{
			name:        "sign with empty claims",
			withPrivate: true,
			withPublic:  false,
			claims:      map[string]interface{}{},
			wantErr:     false,
		},
		{
			name:        "sign with multiple claims",
			withPrivate: true,
			withPublic:  false,
			claims: map[string]interface{}{
				"user":  "test",
				"role":  "admin",
				"email": "test@example.com",
			},
			wantErr: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var privPEM, pubPEM []byte
			if tt.withPrivate {
				privPEM = privateKeyPEM
			}
			if tt.withPublic {
				pubPEM = publicKeyPEM
			}

			manager, err := NewJWTManager(privPEM, pubPEM)
			if err != nil {
				t.Fatalf("Failed to create JWT manager: %v", err)
			}

			token, err := manager.SignToken(tt.claims)

			if tt.wantErr {
				if err == nil {
					t.Errorf("SignToken() expected error but got none")
				} else if tt.errContains != "" && !containsSubstring(err.Error(), tt.errContains) {
					t.Errorf("SignToken() error = %v, should contain %v", err, tt.errContains)
				}
			} else {
				if err != nil {
					t.Errorf("SignToken() unexpected error = %v", err)
				}
				if token == "" {
					t.Error("SignToken() returned empty token")
				}
			}
		})
	}
}

func TestJWTManager_ValidateToken(t *testing.T) {
	privateKeyPEM, publicKeyPEM, err := generateTestKeys()
	if err != nil {
		t.Fatalf("Failed to generate test keys: %v", err)
	}

	// Create manager with both keys
	manager, err := NewJWTManager(privateKeyPEM, publicKeyPEM)
	if err != nil {
		t.Fatalf("Failed to create JWT manager: %v", err)
	}

	// Create a valid token
	validToken, err := manager.SignToken(map[string]interface{}{"user": "test"})
	if err != nil {
		t.Fatalf("Failed to sign token: %v", err)
	}

	tests := []struct {
		name         string
		withPublic   bool
		token        string
		wantErr      bool
		errContains  string
		checkClaims  map[string]interface{}
	}{
		{
			name:        "validate valid token",
			withPublic:  true,
			token:       validToken,
			wantErr:     false,
			checkClaims: map[string]interface{}{"user": "test"},
		},
		{
			name:        "validate without public key",
			withPublic:  false,
			token:       validToken,
			wantErr:     true,
			errContains: "public key not configured",
		},
		{
			name:        "validate invalid token",
			withPublic:  true,
			token:       "invalid.token.here",
			wantErr:     true,
			errContains: "invalid token",
		},
		{
			name:        "validate empty token",
			withPublic:  true,
			token:       "",
			wantErr:     true,
			errContains: "invalid token",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			var pubPEM []byte
			if tt.withPublic {
				pubPEM = publicKeyPEM
			}

			manager, err := NewJWTManager([]byte{}, pubPEM)
			if err != nil {
				t.Fatalf("Failed to create JWT manager: %v", err)
			}

			claims, err := manager.ValidateToken(tt.token)

			if tt.wantErr {
				if err == nil {
					t.Errorf("ValidateToken() expected error but got none")
				} else if tt.errContains != "" && !containsSubstring(err.Error(), tt.errContains) {
					t.Errorf("ValidateToken() error = %v, should contain %v", err, tt.errContains)
				}
			} else {
				if err != nil {
					t.Errorf("ValidateToken() unexpected error = %v", err)
				}
				if claims == nil {
					t.Error("ValidateToken() returned nil claims")
				}
				for key, expectedValue := range tt.checkClaims {
					if actualValue, ok := claims[key]; !ok {
						t.Errorf("ValidateToken() claim %q not found", key)
					} else if actualValue != expectedValue {
						t.Errorf("ValidateToken() claim %q = %v, want %v", key, actualValue, expectedValue)
					}
				}
				// Check standard claims
				if _, ok := claims["iat"]; !ok {
					t.Error("ValidateToken() missing 'iat' claim")
				}
				if _, ok := claims["exp"]; !ok {
					t.Error("ValidateToken() missing 'exp' claim")
				}
			}
		})
	}
}

func TestJWTManager_SignAndValidate(t *testing.T) {
	privateKeyPEM, publicKeyPEM, err := generateTestKeys()
	if err != nil {
		t.Fatalf("Failed to generate test keys: %v", err)
	}

	manager, err := NewJWTManager(privateKeyPEM, publicKeyPEM)
	if err != nil {
		t.Fatalf("Failed to create JWT manager: %v", err)
	}

	// Sign a token
	claims := map[string]interface{}{
		"user":  "testuser",
		"role":  "admin",
		"email": "test@example.com",
	}

	token, err := manager.SignToken(claims)
	if err != nil {
		t.Fatalf("SignToken() error = %v", err)
	}

	// Validate the token
	validatedClaims, err := manager.ValidateToken(token)
	if err != nil {
		t.Fatalf("ValidateToken() error = %v", err)
	}

	// Check custom claims
	for key, expectedValue := range claims {
		if actualValue, ok := validatedClaims[key]; !ok {
			t.Errorf("Missing claim %q", key)
		} else if actualValue != expectedValue {
			t.Errorf("Claim %q = %v, want %v", key, actualValue, expectedValue)
		}
	}

	// Check exp claim is in the future
	if exp, ok := validatedClaims["exp"].(float64); ok {
		if exp <= float64(time.Now().Unix()) {
			t.Error("Token 'exp' claim is not in the future")
		}
		// Check expiration is approximately 1 hour from now
		expectedExp := float64(time.Now().Add(time.Hour).Unix())
		if exp < expectedExp-60 || exp > expectedExp+60 {
			t.Errorf("Token 'exp' claim = %v, expected around %v", exp, expectedExp)
		}
	}
}

// Helper function
func containsSubstring(s, substr string) bool {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

